mapper.sql:
where c.tenant_id = #{tenantId}

    and (lower(c.object_code) like concat('%', lower(#{keyword}), '%')
     or lower(c.object_name) like concat('%', lower(#{keyword}), '%')
     or lower(d.metric_code) like concat('%', lower(#{keyword}), '%')
     or lower(d.metric_name) like concat('%', lower(#{keyword}), '%'))

and c.object_type = #{objectType}
and c.object_id = #{objectId}
and c.metric_definition_id = #{metricDefinitionId}
and c.enabled = #{enabled}
